import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'


function Login() {
  const [form, setForm] = useState({ login: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
      updateCookies();
  }, []);

  const updateCookies = () => {
    const allCookies = {};
    document.cookie.split(';').forEach(cookie => {
      const [key, value] = cookie.trim().split('=');
      if (key) allCookies[key] = value;
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await constFlaskURL.post('/login', {
        login: form.login,
        password: form.password,
      });

      if (response.status === 200) {
        localStorage.setItem('login', response.data.login);

        updateCookies();
        navigate('/main');
      }
    } catch (err) {
      let errorMessage = '';

        if (err.response) {
          errorMessage = err.response.data.message || 'Ошибка входа';
        } else if (err.request) {
          errorMessage = 'Нет ответа от сервера. Проверьте, запущен ли Flask.';
        } else {
          errorMessage = 'Ошибка при отправке запроса';
        }

        setError(errorMessage);
      } finally {
        setLoading(false);
      }
  };

  const handleInputChange = (e) => {
      const { name, value } = e.target;
      setForm(prev => ({
        ...prev,
        [name]: value
      }));
      if (error) setError('');
  };

  return (
    <div className="app-container">
      <div className="app-card">
        <h2 className="app-title">Вход в систему</h2>
        <p className="app-subtitle">Введите логин и пароль</p>
          {error && (
            <div className="error-message">
              <strong>Ошибка:</strong> {error}
            </div>
          )}
          <form onSubmit={handleSubmit} className="app-form">
            <div className="form-group">
              <label htmlFor="login">Логин:</label>
              <input
                type="text"
                name="login"
                value={form.login}
                onChange={handleInputChange}
                className="form-input"
                placeholder="Введите логин"
                required
                disabled={loading}
                autoComplete="username"
                autoFocus
              />
            </div>
            <div className="form-group">
              <label htmlFor="password">Пароль:</label>
              <input
                type="password"
                name="password"
                value={form.password}
                onChange={handleInputChange}
                className="form-input"
                placeholder="Введите пароль"
                required
                disabled={loading}
                autoComplete="current-password"
              />
            </div>
            <button
              type="submit"
              className="login-button"
              disabled={loading || !form.login || !form.password}
            >
              {loading ? 'Вход...' : 'Войти'}
            </button>
          </form>
      </div>
    </div>
  );
}

export default Login;
